#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 15;
ll vis[MAXN], n, a[MAXN];
ll Edge[MAXN][MAXN], minn = 1e18, m;
void dfs(ll sum, int length)
{
	if (length == n)
	{
		minn = min(minn, sum);
		return;
	}
	if(sum>minn)
	{
		return;
	}
	for (int i = 1; i <= n; ++i)
	{
		if (vis[i] == false)
		{
			vis[i] = 1;
			ll summ = 0, k = 0;
			for (int j = 1; j <= n; ++j)
			{

				if (Edge[i][j] && vis[j] == false)
				{
					++k, summ += Edge[i][j];
				}
			}
			dfs(sum + summ * k, length + 1);
			vis[i] = 0;
		}
	}
	return;
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>n>>m;
	memset(Edge,0,sizeof Edge);
	for (int i = 1, u, v, k; i <= m; ++i)
	{
		cin>>u>>v>>k;
		Edge[u][v] = k;
		Edge[v][u] = k;
	}
	dfs(0, 0);
	cout<<minn;
	return false;
}
